## 3. Main Search Page Component

**File**: `src/app/page.tsx`

```typescript:163:163:src/app/page.tsx
"use client";

import { useState, useCallback, useRef } from "react";
import { SearchBar } from "@/components/search-bar";
import { FilterPanel } from "@/components/filter-panel";
import { SearchResults, type SearchHit } from "@/components/search-results";
import { Button } from "@/components/ui/button";
import { Sparkles } from "lucide-react";

export default function Home() {
  const [query, setQuery] = useState("");
  const [role, setRole] = useState("all");
  const [project, setProject] = useState("all");
  const [rerank, setRerank] = useState(false);
  const [hits, setHits] = useState<SearchHit[]>([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);
  const [similarTo, setSimilarTo] = useState<SearchHit | null>(null);

  const roleRef = useRef(role);
  roleRef.current = role;
  const projectRef = useRef(project);
  projectRef.current = project;
  const rerankRef = useRef(rerank);
  rerankRef.current = rerank;

  const doSearch = useCallback(async (searchQuery: string) => {
    if (!searchQuery.trim()) return;
    setLoading(true);
    setSearched(true);
    try {
      const body: Record<string, unknown> = {
        query: searchQuery.trim(),
        topK: 15,
        rerank: rerankRef.current,
      };
      const filters: Record<string, string> = {};
      if (roleRef.current !== "all") filters.role = roleRef.current;
      if (projectRef.current !== "all") filters.project = projectRef.current;
      if (Object.keys(filters).length > 0) body.filters = filters;

      const res = await fetch("/api/search", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setHits(data.hits);
    } catch (err) {
      console.error("Search failed:", err);
      setHits([]);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSearch = useCallback(() => {
    setSimilarTo(null);
    doSearch(query);
  }, [query, doSearch]);

  const handleFindSimilar = useCallback(
    (hit: SearchHit) => {
      setSimilarTo(hit);
      setQuery(hit.chunkText.slice(0, 200));
      doSearch(hit.chunkText);
      window.scrollTo({ top: 0, behavior: "smooth" });
    },
    [doSearch]
  );

  return (
    <div className="mx-auto flex min-h-screen max-w-4xl flex-col gap-6 px-4 py-10">
      <header className="flex flex-col gap-1">
        <h1 className="text-3xl font-bold tracking-tight">Trace Explorer</h1>
        <p className="text-muted-foreground text-sm">
          Semantically search 141K chunks of AI coding agent traces from
          SWE-bench. Find how agents debug, fix, and test real open-source
          issues.
        </p>
      </header>

      <div className="flex flex-col gap-3">
        <SearchBar
          query={query}
          onQueryChange={setQuery}
          onSearch={handleSearch}
          loading={loading}
        />
        <div className="flex flex-wrap items-center gap-3">
          <FilterPanel
            role={role}
            project={project}
            onRoleChange={setRole}
            onProjectChange={setProject}
          />
          <div className="bg-border hidden h-5 w-px sm:block" />
          <Button
            variant={rerank ? "default" : "outline"}
            size="xs"
            onClick={() => setRerank((r) => !r)}
          >
            <Sparkles className="size-3" />
            Rerank
          </Button>
        </div>
      </div>

      {similarTo && (
        <div className="bg-muted/50 flex items-start gap-3 rounded-lg border px-4 py-3">
          <div className="flex-1">
            <p className="text-xs font-medium">
              Finding chunks similar to:
            </p>
            <p className="text-muted-foreground mt-1 text-xs leading-relaxed line-clamp-2">
              {similarTo.chunkText}
            </p>
            <p className="text-muted-foreground mt-1 text-[11px]">
              from {similarTo.project}/{similarTo.issue} &middot; turn{" "}
              {similarTo.turnIndex}
            </p>
          </div>
          <Button
            variant="ghost"
            size="xs"
            onClick={() => {
              setSimilarTo(null);
              setQuery("");
              setHits([]);
              setSearched(false);
            }}
          >
            Clear
          </Button>
        </div>
      )}

      {searched && !loading && hits.length === 0 && (
        <div className="text-muted-foreground py-12 text-center text-sm">
          No results found. Try a different query or adjust filters.
        </div>
      )}

      <SearchResults
        hits={hits}
        loading={loading}
        onFindSimilar={handleFindSimilar}
      />

      {!searched && (
        <div className="text-muted-foreground flex flex-1 flex-col items-center justify-center gap-3 py-20 text-center">
          <div className="text-4xl">&#x1F50D;</div>
          <p className="max-w-sm text-sm">
            Try searching for things like &ldquo;agent debugging a failing
            test&rdquo; or &ldquo;fixing a race condition in Django&rdquo;
          </p>
        </div>
      )}
    </div>
  );
}
```

**Features**:
- Search bar with query input
- Filter panel (role, project)
- Rerank toggle
- "Find similar" from a result
- Loading and empty states

