## 4. Search Results Component

**File**: `src/components/search-results.tsx`

```typescript:127:127:src/components/search-results.tsx
"use client";

import Link from "next/link";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { RoleBadge } from "@/components/role-badge";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowRight, Search } from "lucide-react";

export interface SearchHit {
  id: string;
  score: number;
  chunkText: string;
  role: string;
  traceId: string;
  turnIndex: number;
  chunkIndex: number;
  project: string;
  issue: string;
}

function formatScore(score: number) {
  return (score * 100).toFixed(1) + "%";
}

function truncate(text: string, maxLen = 280) {
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen).trimEnd() + "...";
}

export function SearchResults({
  hits,
  loading,
  onFindSimilar,
}: {
  hits: SearchHit[];
  loading?: boolean;
  onFindSimilar?: (hit: SearchHit) => void;
}) {
  if (loading) {
    return (
      <div className="space-y-4">
        {Array.from({ length: 4 }).map((_, i) => (
          <Card key={i} className="py-4">
            <CardHeader className="pb-0">
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-3 w-32" />
            </CardHeader>
            <CardContent>
              <Skeleton className="h-16 w-full" />
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  if (hits.length === 0) {
    return null;
  }

  return (
    <div className="space-y-3">
      {hits.map((hit) => (
        <Card
          key={hit.id}
          className="group cursor-pointer py-4 transition-colors hover:border-ring/50"
          onClick={() => onFindSimilar?.(hit)}
        >
          <CardHeader className="gap-1 pb-0">
            <div className="flex items-center gap-2">
              <RoleBadge role={hit.role} />
              <CardTitle className="text-sm">
                {hit.project}/{hit.issue}
              </CardTitle>
              <span className="text-muted-foreground ml-auto text-xs tabular-nums">
                {formatScore(hit.score)} match
              </span>
            </div>
            <CardDescription className="text-xs">
              Turn {hit.turnIndex} &middot; Chunk {hit.chunkIndex}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <p className="text-muted-foreground text-sm leading-relaxed">
              {truncate(hit.chunkText)}
            </p>
            <div className="mt-3 flex items-center gap-2 opacity-0 transition-opacity group-hover:opacity-100">
              <Button
                variant="ghost"
                size="xs"
                className="text-muted-foreground gap-1"
                onClick={(e) => {
                  e.stopPropagation();
                  onFindSimilar?.(hit);
                }}
              >
                <Search className="size-3" />
                Find similar
              </Button>
              <Button
                variant="ghost"
                size="xs"
                className="text-muted-foreground gap-1"
                asChild
                onClick={(e) => e.stopPropagation()}
              >
                <Link
                  href={`/trace/${encodeURIComponent(hit.traceId)}?turn=${hit.turnIndex}`}
                >
                  View trace <ArrowRight className="size-3" />
                </Link>
              </Button>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}
```

**Features**:
- Card layout per result
- Role badge, project/issue, match score
- Truncated chunk text (280 chars)
- "Find similar" and "View trace" actions
- Loading skeletons

