## 5. Data Models & Types

### SearchHit Interface
```typescript
export interface SearchHit {
  id: string;              // Pinecone record ID
  score: number;           // Similarity score (0-1)
  chunkText: string;       // The text content of the chunk
  role: string;           // "system" | "user" | "assistant" | "tool"
  traceId: string;        // Full trace ID (e.g., "django__12345.json")
  turnIndex: number;      // Which turn in the conversation
  chunkIndex: number;     // Which chunk within the turn
  project: string;        // Extracted from traceId (e.g., "django")
  issue: string;         // Extracted from traceId (e.g., "12345")
}
```

### Turn Interface
```typescript
export interface Turn {
  turnIndex: number;      // Sequential turn number
  role: string;          // "system" | "user" | "assistant" | "tool"
  text: string;          // Full text of the turn (may be concatenated from chunks)
}
```

### TraceChunk Interface (internal)
```typescript
interface TraceChunk {
  turnIndex: number;
  chunkIndex: number;
  role: string;
  text: string;
}
```

### TraceData Interface
```typescript
interface TraceData {
  traceId: string;
  project: string;
  issue: string;
  turnCount: number;
  turns: Turn[];
}
```

